s3 = boto3.client("s3")
dynamodb = boto3.resource("dynamodb")
sns = boto3.client("sns")
sqs = boto3.client("sqs")

def lambda_handler(event, context):
    action = event.get("action", "noop")
    try:
        if action == "s3_put":
            bucket = os.environ["BUCKET_NAME"]
            key = event["key"]
            body = event.get("body", "")
            s3.put_object(Bucket=bucket, Key=key, Body=body.encode("utf-8"))
            return {"statusCode": 200, "body": json.dumps({"message": "S3 object written"})}

        if action == "ddb_put":
            table_name = os.environ["TABLE_NAME"]
            table = dynamodb.Table(table_name)
            item = event["item"]
            table.put_item(Item=item)
            return {"statusCode": 200, "body": json.dumps({"message": "DynamoDB item written"})}

        if action == "sns_publish":
            topic_arn = os.environ["TOPIC_ARN"]
            message = event["message"]
            sns.publish(TopicArn=topic_arn, Message=message)
            return {"statusCode": 200, "body": json.dumps({"message": "SNS message published"})}

        if action == "sqs_send":
            queue_url = os.environ["QUEUE_URL"]
            message_body = event["message_body"]
            sqs.send_message(QueueUrl=queue_url, MessageBody=message_body)
            return {"statusCode": 200, "body": json.dumps({"message": "SQS message sent"})}

        return {"statusCode": 200, "body": json.dumps({"message": "No action taken"})}

    except ClientError as e:
        return {
            "statusCode": 500,
            "body": json.dumps({"error": e.response.get("Error", {}).get("Message", str(e))}),
        }
    except KeyError as e:
        return {"statusCode": 400, "body": json.dumps({"error": f"Missing required field: {str(e)}"})}